import { NativeManifoldExecutor } from '../src/native-bridge';
import { type ChaosConfig } from '../src/void-game-types';

async function main() {
  console.log('--- GnosisRayon Native Bridge Verification ---');
  
  const executor = new NativeManifoldExecutor();
  const seed = BigInt(Date.now());
  const rounds = 10_000;
  
  const config: ChaosConfig = {
    agentCount: 100_000,
    targetSurvivalRate: 0.15,
    yieldRatio: 0.01,
    penaltyRatio: 0.7751,
    shannonScale: 15.0,
    fatigueThreshold: 100000,
    ventFatality: 0.05,
    blackHoleChance: 0.0005
  };

  console.log(`Executing ${rounds.toLocaleString()} rounds with ${config.agentCount.toLocaleString()} agents...`);
  
  try {
    const start = Date.now();
    const result = await executor.execute(seed, rounds, config);
    const end = Date.now();

    console.log('\n--- Results ---');
    console.log(`Bridge Duration: ${end - start}ms`);
    console.log(`Engine Duration: ${result.durationMs}ms`);
    console.log(`Throughput: ${result.metrics.totalThroughput.toLocaleString()} Sinks`);
    
    // Calculate Ticks/Sec
    // Total Ticks = rounds * agentCount
    const totalTicks = BigInt(rounds) * BigInt(config.agentCount);
    const ticksPerSec = (totalTicks * 1000n) / BigInt(result.durationMs);
    
    console.log(`Aggregate Performance: ${(Number(ticksPerSec) / 1e9).toFixed(2)} Billion Ticks/sec`);
    console.log(`Active Survivors: ${result.activeSurvivors} (${(result.survivalRate * 100).toFixed(2)}%)`);
    console.log(`Final Clinamen Pressure: ${result.clinamenPressure}`);
    
    if (ticksPerSec > 1_000_000_000n) {
      console.log('\n✅ VERIFIED: GnosisRayon is operating at super-relativistic speeds (>1B Ticks/sec).');
    } else {
      console.log('\n⚠️ WARNING: Performance is below the 1B Ticks/sec threshold.');
    }
  } catch (err) {
    console.error('\n❌ FAILED: Bridge Error:', err);
    process.exit(1);
  }
}

main().catch(console.error);
